import { useMemo, useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { addVehicle } from "../../api/vehicleApi";

export default function AddVehicle() {
  const navigate = useNavigate();

  const [vehicle, setVehicle] = useState({
    brand: "",
    type: "",
    year: "",
    price: "",
    status: "available",
    vehicleNumber: "",
    details: "",
  });

  const [images, setImages] = useState([]);
  const previews = useMemo(() => images.map((f) => URL.createObjectURL(f)), [images]);

  useEffect(() => {
    return () => previews.forEach((u) => URL.revokeObjectURL(u));
  }, [previews]);

  const [saving, setSaving] = useState(false);

  const vehicleTypes = ["SUV", "Sedan", "Hatchback", "Truck", "Van", "Coupe"];
  const statuses = ["available", "reserved", "sold"];

  const handleChange = (e) => {
    const { name, value } = e.target;
    setVehicle((prev) => ({ ...prev, [name]: value }));
  };

  const onPickImages = (e) => {
    const files = Array.from(e.target.files || []).slice(0, 4);
    setImages(files);
  };

  const removeImage = (idx) => {
    setImages((prev) => prev.filter((_, i) => i !== idx));
  };

  const submit = async (e) => {
    e.preventDefault();

    const currentYear = new Date().getFullYear();
    const yearNum = Number(vehicle.year);
    const priceNum = Number(vehicle.price);

    if (!vehicle.brand.trim()) return alert("Brand is required");
    if (!vehicle.type) return alert("Vehicle type is required");
    if (!vehicle.year) return alert("Year is required");
    if (Number.isNaN(yearNum)) return alert("Year must be a number");
    if (yearNum > currentYear) return alert(`Year cannot be in the future (max ${currentYear})`);
    if (yearNum < 1900) return alert("Year must be >= 1900");

    if (!vehicle.price) return alert("Price is required");
    if (Number.isNaN(priceNum) || priceNum < 0) return alert("Price must be >= 0");

    const fd = new FormData();
    fd.append("brand", vehicle.brand.trim());
    fd.append("type", vehicle.type);
    fd.append("year", String(yearNum));
    fd.append("price", String(priceNum));
    fd.append("status", vehicle.status);
    fd.append("vehicleNumber", vehicle.vehicleNumber.trim());
    fd.append("details", vehicle.details.trim());

    // images (File[])
    images.forEach((file) => fd.append("images", file));

    await addVehicle(fd);

    try {
      setSaving(true);
      await addVehicle(fd);
      alert("Vehicle added successfully");
      navigate("/vehicles");
    } catch (err) {
      console.log("ADD VEHICLE ERROR", err.response?.status, err.response?.data);
      alert(err.response?.data?.message || "Error adding vehicle");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="container">
      <div className="card cardPad" style={{ maxWidth: 860 }}>
        <div className="row" style={{ marginBottom: 14 }}>
          <div>
            <h2 className="h1">Add Vehicle</h2>
            <div className="sub">Add details and upload up to 4 photos (4:3)</div>
          </div>
        </div>

        <form onSubmit={submit}>
          <div className="grid2">
            <div>
              <label className="label">Brand</label>
              <input className="input" name="brand" value={vehicle.brand} onChange={handleChange} required />
            </div>

            <div>
              <label className="label">Vehicle Type</label>
              <select className="select" name="type" value={vehicle.type} onChange={handleChange} required>
                <option value="">Select Vehicle Type</option>
                {vehicleTypes.map((t) => <option key={t} value={t}>{t}</option>)}
              </select>
            </div>

            <div>
              <label className="label">Year</label>
              <input className="input" name="year" type="number" value={vehicle.year} onChange={handleChange} required />
            </div>

            <div>
              <label className="label">Price (LKR)</label>
              <input className="input" name="price" type="number" value={vehicle.price} onChange={handleChange} required />
            </div>

            <div>
              <label className="label">Status</label>
              <select className="select" name="status" value={vehicle.status} onChange={handleChange}>
                {statuses.map((s) => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>

            <div>
              <label className="label">Vehicle Number</label>
              <input className="input" name="vehicleNumber" value={vehicle.vehicleNumber} onChange={handleChange} />
            </div>
          </div>

          <div style={{ marginTop: 12 }}>
            <label className="label">Details</label>
            <textarea className="textarea" name="details" rows={3} value={vehicle.details} onChange={handleChange} />
          </div>

          <div style={{ marginTop: 14 }}>
            <div className="row">
              <div>
                <div style={{ fontWeight: 800 }}>Photos</div>
                <div className="sub">Max 4 images. We auto-crop server-side to 4:3 (1200×900).</div>
              </div>

              <label className="btn">
                + Add Photos ({images.length}/4)
                <input
                  type="file"
                  accept="image/*"
                  multiple
                  onChange={onPickImages}
                  style={{ display: "none" }}
                  disabled={images.length >= 4}
                />
              </label>
            </div>

            {previews.length > 0 && (
              <div style={{ marginTop: 12, display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12 }}>
                {previews.map((src, idx) => (
                  <div key={src} className="photoCard">
                    <div className="photoBox">
                      <img src={src} alt="preview" className="photoImg" />
                    </div>
                    <button type="button" className="btn btnDanger btnSm" onClick={() => removeImage(idx)}>
                      Remove
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>

          <div style={{ marginTop: 16 }}>
            <button className="btn btnPrimary" disabled={saving}>
              {saving ? "Saving..." : "Save Vehicle"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
